// src/index.js
import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import CssBaseline from "@mui/material/CssBaseline";
import Switch from "@mui/material/Switch";
import "./index.css"; // Keeps your original styling safe

// ==========================================
// 1. CHOOSE YOUR MAIN COMPONENT PATH HERE
// ==========================================
// Look at your VS Code sidebar. If your main file is named "apps.js", leave this as is.
// If your file is named something else, just change the letters inside the quotes below!
import MainLayout from "./apps";

function Root() {
  // 2. State for tracking your Dark / Light theme toggle
  const [darkMode, setDarkMode] = useState(false);

  // 3. Material-UI theme configurations engine
  const theme = createTheme({
    palette: {
      mode: darkMode ? "dark" : "light",
      background: {
        default: darkMode ? "#121212" : "#ffffff",
        paper: darkMode ? "#1e1e1e" : "#ffffff",
      },
      text: {
        primary: darkMode ? "#ffffff" : "#000000",
        secondary: darkMode ? "#aaaaaa" : "#666666",
      },
    },
  });

  return (
    <ThemeProvider theme={theme}>
      {/* CssBaseline makes sure your background body changes when toggled */}
      <CssBaseline />

      {/* 4. Sending the props directly down to your main file layout */}
      <MainLayout darkMode={darkMode} setDarkMode={setDarkMode} />
    </ThemeProvider>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <Root />
  </React.StrictMode>,
);
